import json
import re
from dataclasses import dataclass
from pathlib import Path
from typing import Dict, List, Optional, Tuple

import torch
from peft import PeftModel
from transformers import AutoProcessor, Qwen2_5_VLForConditionalGeneration

DEFAULT_MIN_PIXELS = 256 * 28 * 28
DEFAULT_MAX_PIXELS = 512 * 28 * 28
GRID_SIZE = 1000.0


@dataclass
class ParsedPrediction:
    kind: str
    values: List[float]
    raw_text: str = ""


def _has_weights(path: Path) -> bool:
    if not path.exists() or not path.is_dir():
        return False
    for name in [
        "model.safetensors",
        "model.safetensors.index.json",
        "pytorch_model.bin",
        "pytorch_model.bin.index.json",
    ]:
        if (path / name).exists():
            return True
    return False


def _read_meta(ckpt_dir: Path) -> Dict:
    meta_path = ckpt_dir / "meta.json"
    if meta_path.exists():
        try:
            return json.loads(meta_path.read_text())
        except Exception:
            return {}
    return {}


def resolve_base_model_dir(checkpoint: str) -> str:
    ckpt = Path(checkpoint).resolve()
    ckpt_dir = ckpt if ckpt.is_dir() else ckpt.parent
    meta = _read_meta(ckpt_dir)
    cwd = Path.cwd().resolve()

    candidates = [
        ckpt_dir / "base_model",
        ckpt_dir.parent / "base_model",
        ckpt_dir.parent / "baseline" / "base_model",
        ckpt_dir.parent.parent / "baseline" / "base_model",
        cwd / "checkpoints" / "baseline" / "base_model",
        Path("/workspace/checkpoints/baseline/base_model"),
        Path("/data/base_model/Qwen2.5-VL-3B-Instruct"),
    ]

    for key in ["base_model_dir", "base_model", "base_dir"]:
        val = meta.get(key)
        if not val:
            continue
        p = Path(val)
        if p.is_absolute():
            candidates.append(p)
        else:
            candidates.append((ckpt_dir / p).resolve())
            candidates.append((cwd / p).resolve())

    seen = set()
    ordered = []
    for p in candidates:
        s = str(p)
        if s not in seen:
            ordered.append(p)
            seen.add(s)

    for p in ordered:
        if _has_weights(p):
            return str(p)
    raise FileNotFoundError(f"Could not find packaged base model for checkpoint {checkpoint}; tried: {[str(x) for x in ordered]}")


def load_processor(checkpoint: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    ckpt = Path(checkpoint)
    candidates = []
    if (ckpt / "processor").exists():
        candidates.append(ckpt / "processor")
    candidates.append(ckpt)
    base = Path(resolve_base_model_dir(checkpoint))
    if (base / "processor").exists():
        candidates.append(base / "processor")
    candidates.append(base)

    last_err = None
    for cand in candidates:
        try:
            return AutoProcessor.from_pretrained(
                str(cand),
                local_files_only=True,
                trust_remote_code=False,
                min_pixels=min_pixels,
                max_pixels=max_pixels,
            )
        except Exception as e:
            last_err = e
    raise last_err


def load_model_for_inference(checkpoint: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    base_dir = resolve_base_model_dir(checkpoint)
    processor = load_processor(checkpoint, min_pixels=min_pixels, max_pixels=max_pixels)
    model = Qwen2_5_VLForConditionalGeneration.from_pretrained(
        base_dir,
        torch_dtype=torch.bfloat16,
        local_files_only=True,
        trust_remote_code=False,
        device_map="auto",
    )
    ckpt_dir = Path(checkpoint)
    if ckpt_dir.is_dir() and (ckpt_dir / "adapter_config.json").exists():
        model = PeftModel.from_pretrained(model, str(ckpt_dir), local_files_only=True)
    model.eval()
    return model, processor


def build_messages(instruction: str):
    prompt = (
        "Locate the UI element referred to by the instruction. "
        "Return only coordinates, preferably as <point>x y</point> on a 0-1000 grid. "
        "Acceptable alternatives are <box>x1 y1 x2 y2</box> or plain numbers only. "
        "Do not include any explanation.\n"
        f"Instruction: {instruction}"
    )
    return [
        {
            "role": "user",
            "content": [
                {"type": "image", "image": None},
                {"type": "text", "text": prompt},
            ],
        }
    ]


def _extract_numbers(text: str) -> List[float]:
    return [float(x) for x in re.findall(r"-?\d+(?:\.\d+)?", text)]


def clip_point(x: float, y: float, width: float, height: float) -> List[float]:
    x = max(0.0, min(float(width), float(x)))
    y = max(0.0, min(float(height), float(y)))
    return [x, y]


def clip_bbox(x1: float, y1: float, x2: float, y2: float, width: float, height: float) -> List[float]:
    x1 = max(0.0, min(float(width), float(x1)))
    y1 = max(0.0, min(float(height), float(y1)))
    x2 = max(0.0, min(float(width), float(x2)))
    y2 = max(0.0, min(float(height), float(y2)))
    if x2 < x1:
        x1, x2 = x2, x1
    if y2 < y1:
        y1, y2 = y2, y1
    return [x1, y1, x2, y2]


def _scale_grid_to_abs(vals: List[float], width: float, height: float) -> List[float]:
    out = []
    for i, v in enumerate(vals):
        if abs(v) <= 1.5:
            scaled = v * (width if i % 2 == 0 else height)
        elif 0.0 <= v <= GRID_SIZE + 5:
            scaled = (v / GRID_SIZE) * (width if i % 2 == 0 else height)
        else:
            scaled = v
        out.append(float(scaled))
    return out


def parse_prediction_text(text: str, width: float, height: float) -> ParsedPrediction:
    raw = text.strip()
    t = raw.lower()

    m = re.search(r"<(?:point|click|pt)>(.*?)</(?:point|click|pt)>", t, flags=re.S)
    if m:
        nums = _extract_numbers(m.group(1))
        if len(nums) >= 2:
            vals = _scale_grid_to_abs(nums[:2], width, height)
            return ParsedPrediction("point", clip_point(vals[0], vals[1], width, height), raw)

    m = re.search(r"<(?:box|bbox)>(.*?)</(?:box|bbox)>", t, flags=re.S)
    if m:
        nums = _extract_numbers(m.group(1))
        if len(nums) >= 4:
            vals = _scale_grid_to_abs(nums[:4], width, height)
            return ParsedPrediction("bbox", clip_bbox(*vals, width, height), raw)

    m = re.search(r"<(?:point|click|pt)[^>]*x1?=['\"]?([\d\.\-]+)['\"]?[^>]*y1?=['\"]?([\d\.\-]+)['\"]?[^>]*>", t)
    if m:
        vals = _scale_grid_to_abs([float(m.group(1)), float(m.group(2))], width, height)
        return ParsedPrediction("point", clip_point(vals[0], vals[1], width, height), raw)

    m = re.search(r"<(?:box|bbox)[^>]*x1=['\"]?([\d\.\-]+)['\"]?[^>]*y1=['\"]?([\d\.\-]+)['\"]?[^>]*x2=['\"]?([\d\.\-]+)['\"]?[^>]*y2=['\"]?([\d\.\-]+)['\"]?[^>]*>", t)
    if m:
        vals = _scale_grid_to_abs([float(m.group(i)) for i in range(1, 5)], width, height)
        return ParsedPrediction("bbox", clip_bbox(*vals, width, height), raw)

    nums = _extract_numbers(raw)
    if len(nums) >= 4:
        vals = _scale_grid_to_abs(nums[:4], width, height)
        return ParsedPrediction("bbox", clip_bbox(*vals, width, height), raw)
    if len(nums) >= 2:
        vals = _scale_grid_to_abs(nums[:2], width, height)
        return ParsedPrediction("point", clip_point(vals[0], vals[1], width, height), raw)

    return ParsedPrediction("point", [width / 2.0, height / 2.0], raw)


def row_to_point(row: Dict) -> Tuple[float, float]:
    if row.get("target_point") is not None:
        return float(row["target_point"][0]), float(row["target_point"][1])
    bbox = row.get("target_bbox")
    if bbox is not None:
        return (float(bbox[0]) + float(bbox[2])) / 2.0, (float(bbox[1]) + float(bbox[3])) / 2.0
    return float(row.get("image_width", 1)) / 2.0, float(row.get("image_height", 1)) / 2.0


def generate_raw_text(model, processor, image, instruction: str, max_new_tokens: int = 32) -> str:
    messages = build_messages(instruction)
    prompt = processor.apply_chat_template(messages, tokenize=False, add_generation_prompt=True)
    inputs = processor(text=[prompt], images=[image], return_tensors="pt", padding=True)
    inputs = {k: v.to(model.device) if hasattr(v, "to") else v for k, v in inputs.items()}
    with torch.no_grad():
        out = model.generate(
            **inputs,
            max_new_tokens=max_new_tokens,
            do_sample=False,
            use_cache=True,
        )
    gen_ids = out[:, inputs["input_ids"].shape[1]:]
    text = processor.batch_decode(gen_ids, skip_special_tokens=True, clean_up_tokenization_spaces=False)[0]
    return text.strip()


def generate_prediction(model, processor, image, instruction: str, image_width: float, image_height: float) -> Dict:
    raw = generate_raw_text(model, processor, image, instruction)
    parsed = parse_prediction_text(raw, image_width, image_height)
    if parsed.kind == "bbox":
        x1, y1, x2, y2 = parsed.values
        point = [(x1 + x2) / 2.0, (y1 + y2) / 2.0]
        return {"bbox": parsed.values, "point": point, "raw_text": parsed.raw_text}
    x, y = parsed.values
    return {"point": [x, y], "raw_text": parsed.raw_text}
